import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { HttpClient } from '@angular/common/http';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-candidate-application-detail',
  template: `
  <div class="page">
    <div class="page-header">
      <div>
        <h1 class="page-title">Application Details</h1>
        <p class="muted">Full details, interview schedule and results</p>
      </div>
      <div>
        <button class="btn btn-ghost" (click)="router.navigate(['/candidate/applied'])">Back</button>
        <button class="btn btn-black" (click)="logout()">Logout</button>
      </div>
    </div>

    <div *ngIf="!application" style="padding:20px">Loading...</div>

    <div *ngIf="application" style="margin-top:14px;display:flex;gap:16px;flex-wrap:wrap">
      <div class="card-item" style="flex:1;min-width:320px">
        <h2>{{ internship?.companyName || 'Company' }}</h2>
        <h3 style="margin-top:6px">{{ internship?.title || application?.role }}</h3>
        <p class="muted">Location: {{ internship?.workLocation || '-' }}</p>
        <p style="margin-top:10px">Application ID: <b>{{application.id}}</b></p>
        <p><b>Applied on:</b> {{ formatDate(application.createdAt) }}</p>
        <p *ngIf="application.status"><b>Application Status:</b> {{application.status}}</p>
      </div>

      <div class="card-item" style="flex:1;min-width:320px">
        <h3>Interviews & Results</h3>
        <div class="interview-card" *ngIf="application.interviewStatus || application.l1Date">
          <p><b>Current Stage:</b> {{ application.interviewStatus || 'N/A' }}</p>
          <div *ngIf="application.l1Date" style="margin-top:8px;padding:8px;border:1px solid var(--card-border);border-radius:6px">
            <b>L1 Interview</b><br/>
            Date: {{ formatDate(application.l1Date) }}<br/>
            Time: {{ formatTime(application.l1Time) }}<br/>
            Mode: {{ application.l1Mode }}<br/>
            Result: {{ application.l1Result || 'Pending' }}
          </div>
          <div *ngIf="application.l2Date" style="margin-top:8px;padding:8px;border:1px solid var(--card-border);border-radius:6px">
            <b>L2 Interview</b><br/>
            Date: {{ formatDate(application.l2Date) }}<br/>
            Time: {{ formatTime(application.l2Time) }}<br/>
            Mode: {{ application.l2Mode }}<br/>
            Result: {{ application.l2Result || 'Pending' }}
          </div>
          <div *ngIf="application.hrDate" style="margin-top:8px;padding:8px;border:1px solid var(--card-border);border-radius:6px">
            <b>HR Interview</b><br/>
            Date: {{ formatDate(application.hrDate) }}<br/>
            Time: {{ formatTime(application.hrTime) }}<br/>
            Mode: {{ application.hrMode }}<br/>
            Result: {{ application.hrResult || 'Pending' }}
          </div>
        </div>
      </div>

      <div class="card-item" style="width:100%">
        <h3>Notes & Files</h3>
        <div *ngIf="application.resumeFile">
          <a [href]="'http://localhost:8080/resumes/' + application.resumeFile" target="_blank">View Resume</a>
        </div>
        <div *ngIf="application.offerLetterFile">
          <a [href]="'http://localhost:8080/offers/' + application.offerLetterFile" target="_blank">Offer Letter</a>
        </div>
      </div>
    </div>
  </div>
  `
})
export class CandidateApplicationDetailComponent implements OnInit {
  application: any = null;
  internship: any = null;

  constructor(private route: ActivatedRoute, private http: HttpClient, public router: Router, public auth: AuthService) {}

  ngOnInit() {
    const id = this.route.snapshot.paramMap.get('id');
    if (id) this.load(+id);
  }

  logout() { this.auth.logout(); this.router.navigate(['/']); }

  async load(id: any) {
    try {
      // try single-get
      this.application = await this.http.get<any>(`http://localhost:8080/api/applications/${id}`).toPromise();
    } catch (err) {
      try {
        const all: any = await this.http.get<any[]>('http://localhost:8080/api/applications').toPromise();
        this.application = all.find(a => a.id == id) || null;
      } catch (e) { console.error(e); }
    }

    if (this.application) {
      try { this.internship = await this.http.get<any>(`http://localhost:8080/api/internships/${this.application.internshipId}`).toPromise(); } catch (err) {
        try { const list: any = await this.http.get<any[]>('http://localhost:8080/api/internships').toPromise(); this.internship = list.find((i: any) => i.id === this.application.internshipId) || null; } catch (e) { console.error(e); }
      }
    }
  }

  formatDate(dateString: any) { if (!dateString) return ''; return new Date(dateString).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' }); }
  formatTime(t: any) { if (!t) return ''; return t; }
}
